const raw = items[0].json;
const jsonStr = raw.replace(/^.*?\({/, '{').replace(/}\);?$/, '}');
const data = JSON.parse(jsonStr);
const rows = data.table.rows;

function parseDate(tanggal) {
  const [yyyy, mm, dd] = tanggal.split("-");
  return `${yyyy}-${mm.padStart(2, '0')}-${dd.padStart(2, '0')}`;
}

const today = new Date().toISOString().slice(0, 10);
const header = data.table.cols.map(col => col.label);

const hasil = rows.map(r => {
  const obj = {};
  header.forEach((key, idx) => obj[key] = r.c[idx]?.v);
  return obj;
}).filter(x => x.Tanggal === today);

if (hasil.length === 0) {
  return [{ json: { pesan: '📭 Tidak ada gempa yang tercatat hari ini.' } }];
}

const list = hasil.map(i => `- ${i.Jam} | ${i.Magnitude} SR | ${i.Wilayah}`).join("\n");

return [{ json: { pesan: `📋 *Log Gempa Hari Ini*\n\n${list}` } }];
